func newCmdAndroidLocationProviderIProviderRequestListener_OnProviderRequestChanged() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "on-provider-request-changed",
		Short: "Call OnProviderRequestChanged(provider string, request ProviderRequest)",
		RunE: func(cmd *cobra.Command, args []string) error {
			ctx := context.Background()

			conn, err := cliutil.OpenConn(ctx, cmd)
			if err != nil {
				return err
			}
			defer conn.Close(ctx)

			serviceName, _ := cmd.Flags().GetString("service-name")
			var svc binder.IBinder
			if serviceName != "" {
				svc, err = conn.GetService(ctx, serviceName)
			} else {
				svc, err = cliutil.FindServiceByDescriptor(ctx, conn, "android.location.provider.IProviderRequestListener")
			}
			if err != nil {
				return err
			}

			svcProxy := provider.NewProviderRequestListenerProxy(svc)

			flagProvider, err := cmd.Flags().GetString("provider")
			if err != nil {
				return fmt.Errorf("reading flag provider: %w", err)
			}

			var flagRequest provider.ProviderRequest

			err = svcProxy.OnProviderRequestChanged(ctx, flagProvider, flagRequest)
			if err != nil {
				return err
			}

			mode, _ := cmd.Root().PersistentFlags().GetString("format")
			f := cliutil.NewFormatter(mode, os.Stdout)
			f.Value("status", "ok")
			return nil
		},
	}

	cmd.Flags().String("service-name", "", "ServiceManager name to use instead of descriptor discovery")
	cmd.Flags().String("provider", "", "provider (string)")
	_ = cmd.MarkFlagRequired("provider")

	return cmd
}
